import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Store, Plus, Loader2, Package } from 'lucide-react';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

const PanelCliente = () => {
    const [ofertasPorLocal, setOfertasPorLocal] = useState({});
    const [loading, setLoading] = useState(true);
    const { addToCart, count, total, cart } = useCart();

    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                
                // --- MIRA LA CONSOLA DEL NAVEGADOR (F12) ---
                console.log("DATOS RECIBIDOS DE LA NUBE:", data);

                const agrupado = data.reduce((acc, oferta) => {
                    // Verificamos si el local viene como objeto o ID
                    const localData = oferta.local || {};
                    const nombreLocal = localData.nombre || 'Sin Nombre';
                    
                    if (!acc[nombreLocal]) {
                        acc[nombreLocal] = { info: localData, productos: [] };
                    }
                    acc[nombreLocal].productos.push(oferta);
                    return acc;
                }, {});

                setOfertasPorLocal(agrupado);
            } catch (err) {
                console.error("Error al cargar:", err);
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    if (loading) return (
        <div style={centerState}>
            <Loader2 size={40} color="#e67e22" className="animate-spin" />
            <p>Sincronizando ofertas...</p>
        </div>
    );

    return (
        <div style={container}>
            <header style={headerStyle}>
                <h1 style={titleStyle}>Ofertas Cerca</h1>
                <div style={cartFloatingCard}>
                    <ShoppingCart color="#e67e22" size={20} />
                    <span style={totalText}>${total.toLocaleString()}</span>
                    <div style={badgeCount}>{count}</div>
                </div>
            </header>

            {Object.keys(ofertasPorLocal).map(nombre => (
                <div key={nombre} style={localSection}>
                    <div style={localHeader}>
                        <Store size={18} color="#1e293b" />
                        <h2 style={localTitle}>{nombre}</h2>
                        <span style={distanciaTag}>Activo</span>
                    </div>

                    <div style={scrollContainer}>
                        {ofertasPorLocal[nombre].productos.map(prod => (
                            <div key={prod._id} style={productCard}>
                                <div style={imageBox}>
                                    {/* PRIORIDAD 1: prod.url (Cloudinary) | PRIORIDAD 2: prod.publicId */}
                                    {prod.url ? (
                                        <img 
                                            src={prod.url} 
                                            alt={prod.producto} 
                                            style={imgStyle} 
                                            onError={(e) => { e.target.style.display = 'none'; }} 
                                        />
                                    ) : (
                                        <Package size={40} color="#cbd5e1" />
                                    )}
                                    
                                    {/* ETIQUETA DE STOCK */}
                                    <div style={stockBadge(prod.stock)}>
                                        {prod.stock > 0 ? `${prod.stock} disp.` : 'Agotado'}
                                    </div>
                                </div>

                                <div style={infoBox}>
                                    <h4 style={prodTitle}>{prod.producto}</h4>
                                    <div style={priceContainer}>
                                        <span style={newPrice}>${prod.precioNuevo}</span>
                                        <span style={oldPrice}>${prod.precioViejo}</span>
                                    </div>
                                    <button 
                                        style={prod.stock > 0 ? btnAdd : btnDisabled}
                                        onClick={() => addToCart(prod)}
                                        disabled={prod.stock <= 0}
                                    >
                                        <Plus size={16} /> Agregar
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            ))}
        </div>
    );
};

// --- ESTILOS ---
const container = { padding: '20px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const titleStyle = { fontSize: '1.8rem', fontWeight: '800', color: '#1e293b' };
const cartFloatingCard = { background: '#1e293b', color: 'white', padding: '10px 20px', borderRadius: '50px', display: 'flex', alignItems: 'center', gap: '10px', boxShadow: '0 4px 15px rgba(0,0,0,0.2)' };
const totalText = { fontWeight: 'bold' };
const badgeCount = { background: '#e67e22', padding: '2px 8px', borderRadius: '10px', fontSize: '0.7rem' };

const localSection = { marginBottom: '35px' };
const localHeader = { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px' };
const localTitle = { margin: 0, fontSize: '1.1rem', color: '#1e293b' };
const distanciaTag = { fontSize: '0.7rem', color: '#22c55e', background: '#f0fdf4', padding: '2px 8px', borderRadius: '5px' };

const scrollContainer = { display: 'flex', gap: '15px', overflowX: 'auto', paddingBottom: '10px' };
const productCard = { minWidth: '200px', background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', overflow: 'hidden' };
const imageBox = { height: '140px', background: '#f8fafc', position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const stockBadge = (stock) => ({ position: 'absolute', top: '8px', right: '8px', background: stock > 0 ? 'rgba(34, 197, 94, 0.9)' : 'rgba(239, 68, 68, 0.9)', color: 'white', fontSize: '0.65rem', padding: '2px 6px', borderRadius: '4px', fontWeight: 'bold' });

const infoBox = { padding: '12px' };
const prodTitle = { margin: '0 0 8px 0', fontSize: '0.95rem', fontWeight: 'bold', color: '#334155', textTransform: 'capitalize' };
const priceContainer = { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' };
const newPrice = { fontSize: '1.1rem', fontWeight: '800', color: '#1e293b' };
const oldPrice = { fontSize: '0.8rem', color: '#94a3b8', textDecoration: 'line-through' };

const btnAdd = { width: '100%', background: '#f1f5f9', border: 'none', padding: '8px', borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px', fontWeight: 'bold' };
const btnDisabled = { ...btnAdd, opacity: 0.5, cursor: 'not-allowed' };
const centerState = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '70vh' };

export default PanelCliente;
